INSERT INTO HC_MENU
(
      MENU_SEQ
    , ROLE_ID
    , PAR_ID
    , MENU_ID
    , MENU_CODE
    , MENU_NAME
    , MENU_ENG_NAME
    , MENU_DEPTH
    , MENU_ORDER
    , MENU_STAT
    , MENU_REG_ID
    , MENU_REG_DT
    , MENU_MOD_ID
    , MENU_MOD_DT
    , MENU_URL
)
VALUES
(
    NEXTVAL(HC_MENU_SEQ)
    , #{roleId}
    , #{parId}
    , concat('ID',LPAD((LASTVAL(HC_MENU_SEQ)), 5,'0'))
    , #{menuCode}
    , #{menuName}
    , #{menuEngName}
    , 0
    , #{menuOrder}
    , #{menuStat}
    , #{menuRegId}
    , NOW()
    , #{menuModId}
    , NOW()
    , #{menuUrl}
)

mapper.update:
UPDATE
	HC_MENU
SET
	MENU_MOD_DT = NOW()
	, MENU_CODE = #{menuCode}
	, MENU_NAME = #{menuName}
	, PAR_ID = #{parId}
	, ROLE_ID = #{roleId}
	, MENU_MOD_ID = #{menuModId}

WHERE 1=1
AND MENU_SEQ = #{menuSeq}
AND MENU_ID = #{menuId}

UPDATE
	HC_MENU
SET
	MENU_MOD_DT = NOW()
	, MENU_MOD_ID = #{menuModId}
	, MENU_STAT = 'delete'
WHERE 1=1		
	AND MENU_SEQ = #{menuSeq}
	AND MENU_ID = #{menuId}
